body:
The simple modeling of an sram cell using transif1 switch not working properly... I got this example from Moorby Thomas text book on verilog... the issue is that the transif1 switch can't set the value of  cross coupled inverters (the storage element),  the default drive strength should be strong drive (I think) which should the win the battle again (pull0, pull1) strengthed inverters... notice that if you run the iverilog on the sram code below, you get HiZ at all time
this is incorrect...

/* the code of an sram cell modeling*/
module sram (output dataOut, 
	input address, dataIn, write);
 tri w1, w3, w4;
 bufif1 g1(w1, dataIn, write);
 tranif1 g2(w4, w1, address);
 not (pull0, pull1) g3(w3,w4),g4(w4,w3);
 buf g5(dataOut,w1);
endmodule

module wave_sram #(parameter d=100);
wire dataOut;
reg addr, dataIn, write;

sram c(dataOut, addr, dataIn, write);

initial
begin
	$dumpfile("sram.vcd");
	$dumpvars;
	#d dis;
	#d addr=1;    #d dis;
	#d dataIn=1;  #d dis;
	#d write=1;   #d dis;
	#d write=0;   #d dis;
	#d write='bx; #d dis;
	#d addr ='bx; #d dis;
	#d addr = 1;  #d dis;
	#d write =0;  #d dis;

end

task dis;
 $display($stime,, "addr=%v d_In=%v write=%v d_out = %v ",
	 addr, dataIn, write, dataOut,
	 "(134)=%b%b%b", c.w1, c.w3, c.w4,
	 "  w134=%v %v %v", c.w1, c.w3, c.w4);
endtask
endmodule
